mapper.select:
SELECT COUNT(*) FROM mgmt_office mo INNER JOIN apt_complex ac ON mo.apt_cmplex_no = ac.apt_cmplex_no WHERE mo.use_yn = 'Y'
AND ac.sido_nm = #{sidoNm}
AND ac.sigungu_nm = #{sigunguNm}
AND ( UPPER(mo.mgmt_ofc_nm) LIKE '%' || UPPER(TRIM(#{searchWord})) || '%' OR UPPER(ac.apt_cmplex_nm) LIKE '%' || UPPER(TRIM(#{searchWord})) || '%' )

SELECT * FROM ( SELECT ROWNUM rn , a.* FROM ( SELECT mo.mgmt_ofc_no , mo.mgmt_ofc_nm , ac.apt_cmplex_nm , ac.sido_nm , ac.sigungu_nm , ac.dorojuso FROM mgmt_office mo INNER JOIN apt_complex ac ON mo.apt_cmplex_no = ac.apt_cmplex_no WHERE mo.use_yn = 'Y'
AND ac.sido_nm = #{sidoNm}
AND ac.sigungu_nm = #{sigunguNm}
AND ( UPPER(mo.mgmt_ofc_nm) LIKE '%' || UPPER(TRIM(#{searchWord})) || '%' OR UPPER(ac.apt_cmplex_nm) LIKE '%' || UPPER(TRIM(#{searchWord})) || '%' )
ORDER BY mo.mgmt_ofc_nm ) a WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

SELECT MO.APT_CMPLEX_NO
FROM MGMT_OFFICE MO
WHERE MO.MGMT_OFC_NO = #{mgmtOfcNo}
